#!/usr/bin/env node
// Bundles Node.js built-in polyfills into a Go source file with embedded string constants.
// Run: node scripts/bundle-polyfills.js
const esbuild = require("esbuild");
const fs = require("fs");
const path = require("path");

const polyfills = [
  {
    name: "buffer",
    entry: `
      import { Buffer } from 'buffer';
      globalThis.Buffer = Buffer;
    `,
    exports: "globalThis.Buffer = Buffer;",
  },
  {
    name: "process",
    entry: `
      import process from 'process';
      globalThis.process = process;
    `,
  },
  {
    name: "events",
    entry: `
      import { EventEmitter } from 'events';
      globalThis.EventEmitter = EventEmitter;
    `,
  },
  {
    name: "path",
    entry: `
      import * as path from 'path-browserify';
      globalThis.path = path;
    `,
  },
  {
    name: "util",
    entry: `
      import * as util from 'util';
      globalThis.util = util;
    `,
  },
];

async function bundlePolyfill(p) {
  const result = await esbuild.build({
    stdin: {
      contents: p.entry,
      resolveDir: path.join(__dirname, ".."),
    },
    bundle: true,
    write: false,
    format: "iife",
    platform: "browser",
    minify: true,
    globalName: "__polyfill__",
  });
  return result.outputFiles[0].text;
}

async function main() {
  console.log("Bundling polyfills...");

  const results = {};
  for (const p of polyfills) {
    process.stdout.write(`  bundling ${p.name}...`);
    try {
      results[p.name] = await bundlePolyfill(p);
      console.log(` ${results[p.name].length} bytes`);
    } catch (e) {
      console.log(` FAILED: ${e.message}`);
      results[p.name] = "";
    }
  }

  // Generate Go file
  const goLines = [
    "// Code generated by scripts/bundle-polyfills.js. DO NOT EDIT.",
    "package main",
    "",
    "// Pre-bundled browser polyfills for Node.js built-in modules.",
    "var nodePolyfills = map[string]string{",
  ];

  for (const [name, code] of Object.entries(results)) {
    if (code) {
      // Escape backticks in the code (shouldn't happen in minified output but be safe)
      const escaped = code.replace(/`/g, "`+\"`\"+`");
      goLines.push(`\t"${name}": \`${escaped}\`,`);
    }
  }

  goLines.push("}");
  goLines.push("");

  const outPath = path.join(__dirname, "..", "polyfills_generated.go");
  fs.writeFileSync(outPath, goLines.join("\n"));
  console.log(`\nWrote ${outPath}`);
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});
